export default async function parseNDJSON(stream, onError){
  if (!stream?.pipeThrough) throw new Error('ReadableStream expected');
  const lineSplitter = new TransformStream({
    start(){ this.buf = ''; },
    transform(chunk, controller){
      this.buf += chunk; const parts = this.buf.split('
');
      this.buf = parts.pop() ?? '';
      for (const line of parts){ const t=line.trim(); if (t) controller.enqueue(t); }
    },
    flush(controller){ const t = this.buf.trim(); if (t) controller.enqueue(t); }
  });

  const out = [];
  const reader = stream
    .pipeThrough(new TextDecoderStream())
    .pipeThrough(lineSplitter)
    .getReader();

  while (true){
    const { value, done } = await reader.read(); if (done) break;
    try { out.push(JSON.parse(value)); } catch (e){ onError?.(value, e); }
  }
  try{ reader.releaseLock(); }catch{}
  return out;
}

